import json

path = '/workspace/nexus-mk2/experiments/data/transcripts/0cb4907e-adf3-41d2-92f3-6e88dc76565b.jsonl'
out = []
msg_index = 0
with open(path) as fp:
    for line in fp:
        try:
            d = json.loads(line)
        except:
            continue
        t = d.get('type')
        if t not in ('user', 'assistant'):
            continue
        msg = d.get('message', {})
        content = msg.get('content', '')
        role = msg.get('role') or t
        # extract text
        text_parts = []
        if isinstance(content, list):
            for c in content:
                if not isinstance(c, dict): continue
                if c.get('type') == 'text':
                    text_parts.append(c.get('text', ''))
                elif c.get('type') == 'tool_use':
                    name = c.get('name', '?')
                    inp = c.get('input', {})
                    # summarize
                    if name == 'Bash':
                        text_parts.append(f"[tool: Bash] {inp.get('description','')[:80]}")
                    elif name == 'Read':
                        text_parts.append(f"[tool: Read] {inp.get('file_path','?')}")
                    elif name == 'Write':
                        text_parts.append(f"[tool: Write] {inp.get('file_path','?')}")
                    elif name == 'Edit':
                        text_parts.append(f"[tool: Edit] {inp.get('file_path','?')}")
                    else:
                        text_parts.append(f"[tool: {name}]")
                elif c.get('type') == 'tool_result':
                    pass  # skip
        else:
            text_parts.append(str(content))
        text = '\n'.join(p for p in text_parts if p.strip())
        if not text.strip():
            continue
        if 'agent-setting' in text or 'permission-mode' in text or text.startswith('Caveat:'):
            continue
        if '<system-reminder>' in text or '<command-' in text:
            # keep but trim
            text = text.replace('\n\n\n', '\n')
        msg_index += 1
        out.append({'idx': msg_index, 'role': role, 'text': text})

# Save flat text version
with open('/workspace/nexus-mk2/.scratch/distill-worked-example/raw-conversation.md', 'w') as fp:
    fp.write(f"# Raw conversation — 0cb4907e\n\nTotal messages: {len(out)}\n\n---\n\n")
    for m in out:
        fp.write(f"## [{m['idx']:03d}] {m['role']}\n\n{m['text']}\n\n---\n\n")

print(f"Wrote {len(out)} messages")
print(f"Total chars: {sum(len(m['text']) for m in out)}")
PYEOF
